import os
import pandas as pd
import matplotlib.pyplot as plt
import seaborn as sns

def plot_performance():
    # Path to the CSV file generated by run_inference.py
    csv_path = "results/model_rankings.csv"

    # Check if the file exists
    if not os.path.exists(csv_path):
        print(f"Error: Could not find '{csv_path}'. Please run 'run_inference.py' first.")
        return

    # Read the data
    try:
        df = pd.read_csv(csv_path)
    except Exception as e:
        print(f"Error reading CSV: {e}")
        return

    # Check required columns
    required_columns = ["model_id", "parameters_B", "performance_score", "avg_inferencing_speed_tok_per_s", "avg_wall_time_s", "composite_score"]
    for col in required_columns:
        if col not in df.columns:
            print(f"Error: Missing column '{col}' in the data.")
            return

    # Filter out models that failed (no score)
    df = df.dropna(subset=["performance_score", "parameters_B"])

    if df.empty:
        print("No valid data available to plot after filtering.")
        return

    # Set up the matplotlib figure size
    plt.figure(figsize=(14, 10))
    sns.set_theme(style="whitegrid")

    # 1. Plot Performance vs Parameters
    plt.subplot(2, 2, 1)
    sns.scatterplot(
        data=df,
        x="parameters_B",
        y="performance_score",
        size="composite_score",
        sizes=(50, 400),
        alpha=0.7,
        hue="model_id",
        legend=False
    )
    plt.title("Performance vs. Parameters (Billion)")
    plt.xlabel("Parameters (Billion)")
    plt.ylabel("Performance Score")
    # Add text labels for points
    for i in range(df.shape[0]):
        plt.text(df.parameters_B.iloc[i], df.performance_score.iloc[i],
                 df.model_id.iloc[i].split("/")[-1],
                 fontsize=8, alpha=0.7)

    # 2. Plot Speed vs Parameters
    plt.subplot(2, 2, 2)
    sns.scatterplot(
        data=df,
        x="parameters_B",
        y="avg_inferencing_speed_tok_per_s",
        alpha=0.7,
        hue="model_id",
        legend=False
    )
    plt.title("Inferencing Speed vs. Parameters")
    plt.xlabel("Parameters (Billion)")
    plt.ylabel("Speed (Tokens / s)")

    # 3. Plot Wall Time vs Parameters
    plt.subplot(2, 2, 3)
    sns.scatterplot(
        data=df,
        x="parameters_B",
        y="avg_wall_time_s",
        alpha=0.7,
        hue="model_id",
        legend=False
    )
    plt.title("Wall Time vs. Parameters")
    plt.xlabel("Parameters (Billion)")
    plt.ylabel("Avg Wall Time (s)")

    # 4. Bar plot of Composite Scores
    plt.subplot(2, 2, 4)
    df_sorted = df.sort_values("composite_score", ascending=False)
    # Get just the model name without author
    df_sorted["model_name"] = df_sorted["model_id"].apply(lambda x: x.split("/")[-1])

    sns.barplot(
        data=df_sorted.head(10), # Top 10 to keep it readable
        x="composite_score",
        y="model_name",
        hue="model_name",
        legend=False,
        palette="viridis"
    )
    plt.title("Top 10 Models by Composite Score")
    plt.xlabel("Composite Score")
    plt.ylabel("")

    plt.tight_layout()

    # Save the plot
    output_path = "results/performance_vs_params.png"
    plt.savefig(output_path, dpi=300)
    print(f"Plot saved successfully to '{output_path}'")
    plt.show()

if __name__ == "__main__":
    plot_performance()
